```class Solution {
public:
    string reverseParentheses(string s) {
        string res = "";
        stack<int> st;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '(') st.push(i);
            else if (s[i] == ')') {
                int j = st.top(); st.pop();
                reverse(res.begin() + j, res.end());
                res.erase(res.begin() + j, res.end());
                res += s.substr(j + 1, i - j - 1);
            } else res += s[i];
        }
        return res;
    }
};
```
